#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Speed up the deploy applier (exit-0-safe, SELF-VERIFYING with auto-restore).
Two surgical edits to the per-apply restore-point so deploys stop crawling:
 1) exclude the Python venv (+.git) from the backup tar (huge needless gzip every deploy)
 2) wrap the schema pg_dump in `timeout 25` so it can't hang on import locks
Backs up first; only keeps the edit if `bash -n` passes, else restores the backup."""
import os,sys,json,time,subprocess,shutil
F="/opt/atlas/autopull/atlas-autopull.sh"
out={"kind":"patch_applier","ts":int(time.time())}
try:
    src=open(F).read()
    bak=F+".bak.%d"%int(time.time()); shutil.copy2(F,bak); out["backup"]=bak
    orig=src; changes=[]
    if "opt/atlas/venv" not in src and "--exclude='opt/atlas/data' opt/atlas" in src:
        src=src.replace("--exclude='opt/atlas/data' opt/atlas",
                        "--exclude='opt/atlas/data' --exclude='opt/atlas/venv' --exclude='opt/atlas/.git' opt/atlas",1)
        changes.append("tar: exclude venv/.git")
    if "timeout 25 sudo -u postgres pg_dump" not in src and 'sudo -u postgres pg_dump -s "$PGDB"' in src:
        src=src.replace('sudo -u postgres pg_dump -s "$PGDB"',
                        'timeout 25 sudo -u postgres pg_dump -s "$PGDB"',1)
        changes.append("pg_dump: timeout 25")
    out["changes"]=changes
    if not changes:
        out["result"]="no-op (already patched or pattern not found)"
    else:
        tmp=F+".new"; open(tmp,"w").write(src)
        chk=subprocess.run(["bash","-n",tmp],capture_output=True,text=True)
        out["bash_n_rc"]=chk.returncode; out["bash_n_err"]=chk.stderr.strip()[:200]
        if chk.returncode==0:
            shutil.copymode(F,tmp); os.replace(tmp,F)
            out["result"]="PATCHED + syntax OK"
        else:
            os.remove(tmp); out["result"]="REVERTED (syntax check failed); original untouched"
    # show the two relevant lines now
    out["tar_line"]=subprocess.run(["bash","-lc","grep -n 'files.tar.gz' %s | head -1"%F],capture_output=True,text=True).stdout.strip()
    out["pgdump_line"]=subprocess.run(["bash","-lc","grep -n 'pg_dump -s' %s | head -1"%F],capture_output=True,text=True).stdout.strip()
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/patch-applier.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"patch_applier","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
